map "https://bfd.cms.gov/MappingLanguage/Maps/BFDAuditLog" = "BFD-BFDAuditLog-Map"

uses "http://hl7.org/fhir/StructureDefinition/BFDAuditLog" alias BFDAuditLogLogical as source
uses "http://hl7.org/fhir/StructureDefinition/AuditEvent" alias FHIRAuditEvent as target

group createAuditEvent(source src: BFDAuditLogLogical, target tgt: FHIRAuditEvent) {
    src.timeStamp as time -> tgt.recorded = time "Set recorded time";
    /*
    //Uncomment this block when doing validation. It will be replaced when an HTE AuditEvent profile is published.
    //Until then, it's necessary to hint the profile when validating, but you don't want to publish resources
    //with this as a "profile". 
    src -> tgt.meta = create('Meta') as tgtMeta then {
      src -> tgtMeta.profile = "http://hl7.org/fhir/StructureDefinition/AuditEvent" "add profile";
    } "Create metadata";
    */
    src -> tgt.type = create('Coding') as typeCoding then {
        src -> typeCoding.system = "http://terminology.hl7.org/CodeSystem/iso-21089-lifecycle" "Set system";
        src -> typeCoding.code = "transmit" "Set code for Query (aligned with HTE spec)";
    } "Set type";

    src -> tgt.subtype = c('urn:cms:hte','patient-match-request') "Add event subtype";
    src -> tgt.action = "E" "Add action type";
    src -> tgt.outcome = "0" "Add success outcome"; // we have this because we only log successful events for now.

    src -> tgt.source = create('BackboneElement') as bbElement then{
        src -> bbElement.observer = create('Reference') as tgtReference then {
            src -> tgtReference.display = "CMS Beneficiary FHIR Data Server" "Add source of AuditEvent as BFD";
        } "Create source";
    } "Add source";

    src -> tgt.purposeOfEvent = cc("http://terminology.hl7.org/CodeSystem/v3-ActReason", "PATRQT") "Set purpose of event";

    src -> tgt.agent = create('BackboneElement') as agent then {
        src -> agent.requestor = true "Set requestor";
        src.clientName as name -> agent.name = name "Set client name";
        src.clientName as altId -> agent.altId = altId "Set alternate id (client name). May be changed to clientId in future";
        src.clientIp as ip -> agent.network = create('BackboneElement') as network then {
            ip -> network.address = ip "Set IP address";
            src -> network.type = "2" "Set network type (IP address)";
        } "Set network";
    } "Set agent";

    src.matchedBeneSk as beneSk -> tgt.entity = create('BackboneElement') as entity then {
        src -> entity.type = create('Coding') as entityType then {
            src -> entityType.system = "http://hl7.org/fhir/resource-types" "Set system";
            src -> entityType.code = "Patient" "Set code for Patient";
            src -> entityType.display = "Patient" "Set display";
        } "Set entity type";
        src -> entity.role = create('Coding') as entityRole then {
            src -> entityRole.system = "http://terminology.hl7.org/CodeSystem/object-role" "Set system";
            src -> entityRole.code = "1" "Set code for Patient";
            src -> entityRole.display = "Patient" "Set display";
        } "Set entity role";
        beneSk -> entity.what = create('Reference') as tgtRef then {
            beneSk -> tgtRef.reference = append("Patient/", beneSk) "Set patient reference";
        } "Add reference";
        src -> entity.name = "Match Info" "add name";
        src -> entity.description = "The detail elements refer to the matching algorithm + version combination that resulted in a unique match." "add description";

        src.finalDetermination as det -> entity.detail = create('BackboneElement') as tgtDetail then {
            src -> tgtDetail.type = "matchAlgorithm" "note as algorithm";
            det -> tgtDetail.value = det "add algorithm";
        } "Add algorithm version";
        src -> entity.detail = create('BackboneElement') as tgtDetail then {
            src -> tgtDetail.type = "matchAlgorithmVersion" "note as version";
            src -> tgtDetail.value = "3.2.2" "note version, hardcoded to 3.2.2 for now";
        } "Add versioning info";
    } "finish entity";

}
